class AuthPreferences {
  static const String _isAuthenticatedKey = 'is_authenticated';
  static const String _authMethodKey = 'auth_method';

  static Future<void> setAuthenticated(bool value,
      {String method = 'biometric'}) async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setBool(_isAuthenticatedKey, value);
    await prefs.setString(_authMethodKey, method);
  }

  static Future<bool> isAuthenticated() async {
    final prefs = await SharedPreferences.getInstance();
    return prefs.getBool(_isAuthenticatedKey) ?? false;
  }

  static Future<String?> getAuthMethod() async {
    final prefs = await SharedPreferences.getInstance();
    return prefs.getString(_authMethodKey);
  }

  static Future<void> clearAuth() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.remove(_isAuthenticatedKey);
    await prefs.remove(_authMethodKey);
  }
}

